1431   if (A.isNaN())
1432     return A;
1433   if (B.isNaN())
1434     return B;
1435   if (A.isZero() && B.isZero() && (A.isNegative() != B.isNegative()))
1436     return A.isNegative() ? B : A;
1437   return A < B ? B : A;
